  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ==========================================\n// MODELO: Usuário\n// ==========================================\nmodel User {\n  id        String   @id @default(uuid())\n  nome      String\n  email     String   @unique\n  senha     String\n  cargo     String?\n  role      UserRole @default(COLABORADOR)\n  ativo     Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  configuracao   Configuracao?\n  registros      RegistroPonto[]\n  justificativas Justificativa[]\n  bancoHoras     BancoHoras?\n  logs           Log[]\n\n  @@map(\"users\")\n}\n\n// ==========================================\n// MODELO: Configurações do usuário\n// ==========================================\nmodel Configuracao {\n  id                     String   @id @default(uuid())\n  userId                 String   @unique\n  jornadaPadraoMinutos   Int      @default(480) // 8h = 480min\n  horarioEntrada         String   @default(\"08:00\") // formato HH:MM\n  horarioSaida           String   @default(\"17:00\")\n  intervaloMinimoMinutos Int      @default(60) // 1h mínimo CLT\n  toleranciaMinutos      Int      @default(10) // tolerância de registro\n  notifAntecedenciaMin   Int      @default(15) // notificar X min antes\n  notifHoraExtraMin      Int      @default(30) // perguntar hs extras a cada X min\n  diasTrabalho           Json     @default(\"[1,2,3,4,5]\") // 0=Dom, 6=Sab\n  limiteHoraExtraDia     Int      @default(120) // 2h = 120min CLT\n  limiteHoraSemana       Int      @default(2640) // 44h = 2640min CLT\n  updatedAt              DateTime @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"configuracoes\")\n}\n\n// ==========================================\n// MODELO: Registro de Ponto\n// ==========================================\nmodel RegistroPonto {\n  id                  String      @id @default(uuid())\n  userId              String\n  data                DateTime    @db.Date\n  entrada             DateTime?\n  inicioIntervalo     DateTime?\n  fimIntervalo        DateTime?\n  saida               DateTime?\n  horasTrabalhadasMin Int? // calculado em minutos\n  horasExtrasMin      Int? // calculado em minutos\n  intervaloDuracaoMin Int? // duração real do intervalo\n  status              StatusPonto @default(NORMAL)\n  observacao          String?\n  intervaloAdiado     Boolean     @default(false)\n  createdAt           DateTime    @default(now())\n  updatedAt           DateTime    @updatedAt\n\n  user            User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  justificativa   Justificativa? @relation(fields: [justificativaId], references: [id])\n  justificativaId String?\n  logs            Log[]\n\n  @@unique([userId, data])\n  @@index([userId, data])\n  @@map(\"registros_ponto\")\n}\n\n// ==========================================\n// MODELO: Justificativa de Ausência (Art. 473 CLT)\n// ==========================================\nmodel Justificativa {\n  id             String              @id @default(uuid())\n  userId         String\n  tipo           TipoJustificativa\n  motivo         String\n  anexoUrl       String? // Caminho do PDF/Imagem\n  dataInicio     DateTime            @db.Date\n  dataFim        DateTime            @db.Date\n  status         StatusJustificativa @default(PENDENTE)\n  acaoRH         AcaoRH? // Decisão sobre o tempo\n  observacaoRH   String?\n  confirmadoUser Boolean             @default(false)\n  createdAt      DateTime            @default(now())\n  updatedAt      DateTime            @updatedAt\n\n  user      User            @relation(fields: [userId], references: [id], onDelete: Cascade)\n  registros RegistroPonto[]\n\n  @@map(\"justificativas\")\n}\n\n// ==========================================\n// MODELO: Banco de Horas\n// ==========================================\nmodel BancoHoras {\n  id           String   @id @default(uuid())\n  userId       String   @unique\n  saldoMinutos Int      @default(0)\n  updatedAt    DateTime @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"banco_horas\")\n}\n\n// ==========================================\n// MODELO: Log de eventos\n// ==========================================\nmodel Log {\n  id         String       @id @default(uuid())\n  userId     String\n  registroId String?\n  tipoEvento TipoEvento\n  origem     OrigemEvento @default(MANUAL)\n  timestamp  DateTime     @default(now())\n  detalhes   Json?\n  ip         String?\n\n  user     User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  registro RegistroPonto? @relation(fields: [registroId], references: [id], onDelete: SetNull)\n\n  @@index([userId, timestamp])\n  @@map(\"logs\")\n}\n\n// ==========================================\n// ENUMS\n// ==========================================\nenum UserRole {\n  COLABORADOR\n  ADMIN_RH\n}\n\nenum StatusPonto {\n  NORMAL\n  FALTA\n  ATESTADO\n  FERIADO\n  FOLGA\n  MEIO_PERIODO\n}\n\nenum TipoJustificativa {\n  ATESTADO_MEDICO\n  ATESTADO_ACOMPANHANTE\n  OBITO\n  CASAMENTO\n  NASCIMENTO_FILHO\n  DOACAO_SANGUE\n  ALISTAMENTO_MILITAR\n  VESTIBULAR\n  JUSTICA\n  CONVOCACAO_ELEITORAL\n  OUTROS\n}\n\nenum StatusJustificativa {\n  PENDENTE\n  EM_REVISAO\n  APROVADO\n  REJEITADO\n}\n\nenum AcaoRH {\n  ABONAR // Paga o dia, não desconta banco\n  COMPENSAR // Adiciona débito ao Banco de Horas\n  DESCONTAR // Desconto direto em folha (falta)\n}\n\nenum TipoEvento {\n  ENTRADA\n  INICIO_INTERVALO\n  FIM_INTERVALO\n  SAIDA\n  HORA_EXTRA_INICIO\n  HORA_EXTRA_FIM\n  NOTIFICACAO_ENVIADA\n  AUTO_REGISTRO\n  AJUSTE_MANUAL\n  LOGIN\n  LOGOUT\n  JUSTIFICATIVA_UPLOAD\n  JUSTIFICATIVA_VALIDADA\n}\n\nenum OrigemEvento {\n  MANUAL\n  AUTOMATICO\n  SISTEMA\n}\n",
